import React from "react";
import { Link } from "react-router-dom";

function Sidebar() {
  const role = localStorage.getItem("role");

  let menu = [];

  if (role === "admin") {
    menu = ["Dashboard", "Manage Users", "Manage Courses", "Reports", "Settings"];
  } else if (role === "instructor") {
    menu = ["Dashboard", "My Courses", "Assignments", "Students"];
  } else if (role === "student") {
    menu = ["Dashboard", "My Courses", "Assignments", "Grades"];
  } else if (role === "content") {
    menu = ["Dashboard", "Create Content", "Edit Content", "Published Materials"];
  }

  return (
    <div
      className="d-flex flex-column bg-dark text-white p-3"
      style={{ minHeight: "100vh", width: "220px" }}
    >
      <h5 className="text-center mb-4">{role.toUpperCase()}</h5>
      {menu.map((item, idx) => (
        <Link
          key={idx}
          to="/"
          className="text-white text-decoration-none mb-2 p-2 rounded hover-bg"
        >
          {item}
        </Link>
      ))}
    </div>
  );
}

export default Sidebar;
